import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";
import api, { BASE } from './api';

const ChatSocket = ({ goBack }) => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [friends, setFriends] = useState([]);
  const [selectedFriend, setSelectedFriend] = useState(null);
  const [privateMessages, setPrivateMessages] = useState({});
  const [chatMode, setChatMode] = useState("public");
  const [selectedImage, setSelectedImage] = useState(null);
  const [notifications, setNotifications] = useState([]);
  const [currentUserId, setCurrentUserId] = useState(null);

  const messagesEndRef = useRef(null);
  const fileInputRef = useRef(null);
  const cameraInputRef = useRef(null);
  const friendsFetchedRef = useRef(false);
  const socketRef = useRef(null);

  const getToken = () => localStorage.getItem("token");

  // Lấy currentUserId an toàn
  useEffect(() => {
    const token = getToken();
    if (token) {
      try {
        const payload = JSON.parse(atob(token.split(".")[1]));
        setCurrentUserId(payload.id);
      } catch (err) {
        console.error("Invalid token:", err);
      }
    }
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, privateMessages]);

  const fetchFriends = async () => {
    try {
      const data = await api.fetchFriends();
      setFriends(data.friends || []);
    } catch (err) {
      console.error('Error fetching friends:', err);
    }
  };

  const fetchPrivateMessages = async (friendId) => {
    try {
      const data = await api.fetchPrivateMessages(friendId);
      setPrivateMessages((prev) => ({ ...prev, [friendId]: data.messages || [] }));
    } catch (err) {
      console.error('Error fetching private messages:', err);
    }
  };

  const sendPrivateMessage = async (receiverId, text, mediaUrl = null) => {
    try {
      const data = await api.sendPrivateMessage(receiverId, text, mediaUrl);
      if (data && data.data) {
        // Backend returns { data: fullMessage }
        const message = data.data;
        setPrivateMessages((prev) => ({
          ...prev,
          [receiverId]: [...(prev[receiverId] || []), message],
        }));
      }
    } catch (err) {
      console.error('Error sending private message:', err);
    }
  };

  // Khởi tạo socket (chỉ khi có token)
  useEffect(() => {
    const token = getToken();
    console.log("🔧 Socket init effect - token:", token ? "exists" : "missing");
    if (!token) {
      console.log("❌ No token, socket init skipped");
      return;
    }

    console.log("🚀 Initializing socket with BASE:", BASE);

    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }

    const newSocket = io(BASE, {
      auth: { token },
      transports: ["websocket"],
      reconnection: true,
      reconnectionAttempts: 5,
      reconnectionDelay: 1000,
    });

    newSocket.on("connect", () => {
      console.log("✅ Socket connected");
      setIsConnected(true);
    });
    newSocket.on("disconnect", (reason) => {
      console.log("❌ Socket disconnected:", reason);
      setIsConnected(false);
      if (reason === "io server disconnect") newSocket.connect();
    });
    newSocket.on("connect_error", (err) => {
      console.error("❌ Connection error:", err);
      setIsConnected(false);
    });

    newSocket.on("message", (msg) => {
      console.log("📨 Received message from socket:", msg);
      setMessages((prev) => [...prev, msg]);
    });

    newSocket.on("presence", setOnlineUsers);

    newSocket.on("private_message", (data) => {
      const { message, sender_id, receiver_id } = data;
      if (currentUserId && receiver_id === currentUserId) {
        const friendId = sender_id;
        setPrivateMessages((prev) => ({
          ...prev,
          [friendId]: [...(prev[friendId] || []), message],
        }));
        if (!selectedFriend || selectedFriend.id !== friendId) {
          const friend = friends.find((f) => f.id === friendId);
          if (friend) {
            setNotifications((prev) => [
              ...prev,
              {
                id: `${Date.now()}-${Math.random()}`,
                type: "private_message",
                from: friend?.display_name || friend?.username || 'Người dùng',
                message: message.text || "Sent an image",
                timestamp: new Date(),
              },
            ]);

            if ("Notification" in window && Notification.permission === "granted") {
              const notification = new Notification(`Tin nhắn từ ${friend?.display_name || friend?.username || 'Người dùng'}`, {
                body: message.text || "Đã gửi hình ảnh",
                icon: "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png",
                tag: `private-message-${friendId}`,
              });
              setTimeout(() => notification.close(), 5000);
            }
          }
        }
      }
    });

    socketRef.current = newSocket;
    setSocket(newSocket);
    return () => newSocket.disconnect();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (!friendsFetchedRef.current) {
      fetchFriends();
      friendsFetchedRef.current = true;
    }
  }, []);

  useEffect(() => {
    if (chatMode === 'public') {
      api.fetchMessages().then((data) => setMessages(data.messages || [])).catch(console.error);
    }
  }, [chatMode]);

  useEffect(() => {
    if (selectedFriend && chatMode === "private") fetchPrivateMessages(selectedFriend.id);
  }, [selectedFriend, chatMode]);

  const sendMessage = () => {
    if (!input.trim()) return;
    console.log("📤 Sending message:", { chatMode, input, socketConnected: socketRef.current?.connected, selectedFriend });
    if (chatMode === "public" && socketRef.current) {
      socketRef.current.emit("message", { text: input });
      setInput("");
    } else if (chatMode === "private" && selectedFriend) {
      sendPrivateMessage(selectedFriend.id, input);
      setInput("");
    }
  };

  const handleKeyPress = (e) => e.key === "Enter" && sendMessage();
  const selectFriend = (friend) => {
    setSelectedFriend(friend);
    setChatMode("private");
  };
  const switchToPublic = () => {
    setChatMode("public");
    setSelectedFriend(null);
  };

  const handleImageSelect = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => sendImageMessage(e.target.result);
      reader.readAsDataURL(file);
    }
  };
  const handleCameraCapture = handleImageSelect;

  const sendImageMessage = async (imageData) => {
    try {
      // Upload image to Cloudinary via backend
      const uploadResponse = await api.uploadMessageImage(imageData);
      if (!uploadResponse || !uploadResponse.url) {
        console.error('Failed to upload image');
        return;
      }

      const mediaUrl = uploadResponse.url;

      if (chatMode === "public" && socketRef.current) {
        socketRef.current.emit("message", { text: "", media_url: mediaUrl, message_type: "image" });
      } else if (chatMode === 'private' && selectedFriend) {
        await sendPrivateMessage(selectedFriend.id, '', mediaUrl);
      }
      setSelectedImage(null);
    } catch (err) {
      console.error('Error sending image message:', err);
    }
  };

  const deleteMessage = async (messageId, isPrivate = false) => {
    try {
      await api.deleteMessage(messageId, isPrivate);
      if (isPrivate && selectedFriend) {
        setPrivateMessages((prev) => ({
          ...prev,
          [selectedFriend.id]: prev[selectedFriend.id].filter((msg) => msg.id !== messageId),
        }));
      } else {
        setMessages((prev) => prev.filter((msg) => msg.id !== messageId));
      }
    } catch (err) {
      console.error('Error deleting message:', err);
    }
  };

  const currentMessages =
    chatMode === "public"
      ? messages
      : selectedFriend
      ? privateMessages[selectedFriend.id] || []
      : [];

  return (
    <div className="flex h-screen bg-[#f0f2f5]">
      {/* Sidebar */}
      <div className="w-64 bg-white shadow-lg flex flex-col">
        <div className="p-3 border-b bg-white">
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-lg font-bold text-gray-900">Chats</h2>
            <button onClick={goBack} className="text-gray-500 hover:text-gray-700 text-base">←</button>
          </div>
          <input
            type="text"
            placeholder="Tìm kiếm..."
            className="w-full px-3 py-2 bg-gray-100 rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <div className="flex gap-1 mb-3 mt-2">
            <button
              onClick={switchToPublic}
              className={`flex-1 py-2 px-3 rounded-lg text-sm font-medium ${
                chatMode === "public" ? "bg-[#0084ff] text-white" : "bg-gray-200 text-gray-700 hover:bg-gray-300"
              }`}
            >
              Chat chung
            </button>
            <button
              onClick={() => setChatMode("private")}
              className={`flex-1 py-2 px-3 rounded-lg text-sm font-medium ${
                chatMode === "private" ? "bg-[#0084ff] text-white" : "bg-gray-200 text-gray-700 hover:bg-gray-300"
              }`}
            >
              Nhắn tin
            </button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto">
          {chatMode === "private" ? (
            friends.length === 0 ? (
              <div className="text-gray-500 text-sm text-center py-8">Chưa có bạn bè</div>
            ) : (
              // Filter out invalid/undefined entries, then map
              friends.filter(Boolean).map((friend) => {
                const isOnline = onlineUsers.some((u) => u.id === friend.id);
                const hasNotification = notifications.some((n) => n.from === (friend?.display_name || friend?.username || ''));
                const lastMessage = privateMessages[friend.id]?.slice(-1)[0];
                return (
                  <div
                    key={friend.id}
                    onClick={() => {
                      selectFriend(friend);
                      setNotifications((prev) => prev.filter((n) => n.from !== (friend?.display_name || friend?.username || '')));
                    }}
                    className={`flex items-center gap-2 p-2 cursor-pointer hover:bg-gray-50 ${
                      selectedFriend?.id === friend.id ? "bg-blue-50 border-r-4 border-[#0084ff]" : ""
                    } ${hasNotification ? "bg-yellow-50" : ""}`}
                  >
                    <div className="relative">
                      <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png" alt="avatar" className="w-12 h-12 rounded-full" />
                      {isOnline && <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white rounded-full"></div>}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between">
                        <div className="font-medium text-gray-900 truncate">{friend?.display_name || friend?.username || 'Người dùng'}</div>
                        {lastMessage && (
                          <div className="text-xs text-gray-500">
                            {new Date(lastMessage.created_at).toLocaleTimeString("vi-VN", { hour: "2-digit", minute: "2-digit" })}
                          </div>
                        )}
                      </div>
                      <div className="text-sm text-gray-600 truncate">
                        {lastMessage ? (lastMessage.media_url ? "📸 Hình ảnh" : lastMessage.text) : "Chưa có tin nhắn"}
                      </div>
                    </div>
                    {hasNotification && <div className="w-2 h-2 bg-red-500 rounded-full"></div>}
                  </div>
                );
              })
            )
          ) : (
            <div className="p-4 text-center py-8">
              <div className="text-gray-500 text-sm mb-2">Chat chung</div>
              <div className="text-xs text-gray-400">{onlineUsers.length} người online</div>
            </div>
          )}
        </div>
      </div>

      {/* Chat area */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <div className="bg-white shadow-sm p-3 border-b">
          <div className="flex items-center gap-3">
            {chatMode === "private" && selectedFriend ? (
              <>
                <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png" alt="avatar" className="w-8 h-8 rounded-full" />
                <div>
                  <h3 className="font-semibold text-sm">{selectedFriend?.display_name || selectedFriend?.username || 'Người dùng'}</h3>
                  <p className="text-xs text-gray-500">{onlineUsers.some((u) => u.id === selectedFriend?.id) ? "Online" : "Offline"}</p>
                </div>
              </>
            ) : (
              <h3 className="font-semibold text-sm">Chat chung</h3>
            )}
          </div>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 bg-[#f0f2f5]">
            {currentMessages.map((msg, idx) => {
            const isCurrentUser = msg.sender_id === currentUserId || msg.from?.id === currentUserId;
            const displayName = msg.from?.display_name || msg.from?.username || 'Người dùng';
            const messageText = msg.text || msg.content || '';
            return (
              <div key={`${msg.id || idx}`} className={`flex mb-4 ${isCurrentUser ? "justify-end" : "justify-start"}`}>
                {!isCurrentUser && (
                  <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png" alt="avatar" className="w-8 h-8 rounded-full flex-shrink-0 mr-2 self-end" />
                )}
                <div className={`flex flex-col ${isCurrentUser ? "items-end" : "items-start"} max-w-xs lg:max-w-md`}>
                    {chatMode === "public" && !isCurrentUser && <div className="text-xs text-gray-500 mb-1">{displayName}</div>}
                  <div className={`relative group px-3 py-2 rounded-2xl max-w-full ${isCurrentUser ? "bg-[#0084ff] text-white rounded-br-md" : "bg-white text-gray-900 rounded-bl-md shadow-sm"}`}>
                    {msg.media_url ? (
                      <img src={msg.media_url} alt="Shared" className="max-w-full max-h-64 rounded-lg cursor-pointer" onClick={() => window.open(msg.media_url, "_blank")} />
                    ) : (
                      <div className="text-sm leading-relaxed break-words">{messageText}</div>
                    )}
                    {isCurrentUser && msg.id && (
                      <button onClick={() => deleteMessage(msg.id, chatMode === "private")} className="absolute -top-2 -right-2 text-red-500 hover:text-red-700 opacity-0 group-hover:opacity-100 transition-opacity bg-white rounded-full p-1 shadow-sm" title="Xóa tin nhắn">
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                          <path d="M9 3v1H5v2h1v13a2 2 0 002 2h8a2 2 0 002-2V6h1V4h-4V3H9m0 5v9m4-9v9" />
                        </svg>
                      </button>
                    )}
                  </div>
                  {msg.created_at && (
                    <div className="text-xs text-gray-500 mt-1">
                      {new Date(msg.created_at).toLocaleTimeString("vi-VN", { hour: "2-digit", minute: "2-digit" })}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div className="bg-white border-t p-3">
          <div className="flex gap-2 items-end">
            <button onClick={() => fileInputRef.current?.click()} className="text-gray-500 hover:text-gray-700 p-2 rounded-full hover:bg-gray-100 transition-colors" disabled={chatMode === "private" && !selectedFriend}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M21.5 2v6h-6M2.5 22v-6h6M2 11.5a10 10 0 0 1 18.8-4.3M22 12.5a10 10 0 0 1-18.8 4.2" />
              </svg>
            </button>
            <button onClick={() => cameraInputRef.current?.click()} className="text-gray-500 hover:text-gray-700 p-2 rounded-full hover:bg-gray-100 transition-colors">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z" />
                <circle cx="12" cy="13" r="4" />
              </svg>
            </button>
            <input type="file" ref={fileInputRef} className="hidden" onChange={handleImageSelect} />
            <input type="file" accept="image/*" capture="environment" ref={cameraInputRef} className="hidden" onChange={handleCameraCapture} />
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyPress}
              placeholder="Nhập tin nhắn..."
              className="flex-1 border rounded-full px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
              disabled={chatMode === "private" && !selectedFriend}
            />
            <button onClick={sendMessage} className="bg-blue-500 text-white px-4 py-2 rounded-full hover:bg-blue-600 transition-colors" disabled={!input.trim() || (chatMode === "private" && !selectedFriend)}>Gửi</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatSocket;
